Agent SQL:
SELECT name
FROM projects
WHERE country = 'France';

SELECT *
FROM sites
WHERE operating_rate > 0.8 AND deleted = FALSE;

SELECT *
FROM sites
WHERE deleted = TRUE;

SELECT project_id, name, country, client_company_name, time_zone, city, start_date, description
FROM projects
WHERE description IS NULL OR description = '';

SELECT config_id, gateway_id, file_name, ftp_ip, regex_variables, active, created_at
FROM configs
WHERE active = TRUE;

SELECT time_zone, COUNT(*) 
FROM gateways 
GROUP BY time_zone;

SELECT site_id, name, type, extent, start_date, previsional_end, project_id
FROM sites
WHERE previsional_end < '2025-01-01' AND deleted = FALSE;

SELECT name, installation_date
FROM gateways
ORDER BY installation_date DESC NULLS LAST;

SELECT COUNT(*) 
FROM configs 
WHERE regex_variables IS NOT NULL;

SELECT measurement_id, variable_id, sensor_id, value, timestamp
FROM raw_measurements
WHERE timestamp >= NOW() - INTERVAL '1 hour';

SELECT config_id, gateway_id, file_name, regex_variables, active, created_at
FROM configs
WHERE regex_variables IS NOT NULL;

SELECT sqrt(power(g1.x - g2.x, 2) + power(g1.y - g2.y, 2) + power(g1.z - g2.z, 2))
FROM gateways g1, gateways g2
WHERE g1.gateway_id = 1 AND g2.gateway_id = 2;

SELECT *
FROM configs
WHERE ftp_ip LIKE '192.168.1.%';
